import os
import platform
import configparser
from pathlib import Path


def get_pip_config_path():
    system = platform.system()
    
    if system == "Windows":
        config_dir = Path(os.environ.get('APPDATA', ''), 'pip')
        config_file = config_dir / 'pip.ini'
    else:
        config_dir = Path.home() / '.config' / 'pip'
        config_file = config_dir / 'pip.conf'
    
    return config_dir, config_file


def create_pip_config(
    internal_pypi_url='https://pypi.internal.company.com/simple',
    fallback_pypi_url='https://pypi.org/simple',
    trusted_hosts=None,
    timeout=60,
    retries=5,
    cache_dir=None,
    disable_pip_version_check=True,
    no_color=False
):
    if trusted_hosts is None:
        trusted_hosts = ['pypi.internal.company.com']
    
    config = configparser.ConfigParser()
    
    config['global'] = {
        'timeout': str(timeout),
        'retries': str(retries),
    }
    
    if disable_pip_version_check:
        config['global']['disable-pip-version-check'] = 'true'
    
    if no_color:
        config['global']['no-color'] = 'true'
    
    if cache_dir:
        config['global']['cache-dir'] = cache_dir
    
    config['install'] = {
        'index-url': internal_pypi_url,
        'extra-index-url': fallback_pypi_url,
    }
    
    if trusted_hosts:
        config['install']['trusted-host'] = '\n' + '\n'.join(trusted_hosts)
    
    config['list'] = {
        'format': 'columns'
    }
    
    config['freeze'] = {
        'timeout': '10'
    }
    
    config_dir, config_file = get_pip_config_path()
    
    config_dir.mkdir(parents=True, exist_ok=True)
    
    with open(config_file, 'w') as f:
        config.write(f)
    
    if platform.system() != "Windows":
        os.chmod(config_file, 0o600)
    
    return config_file


def create_pip_config_with_auth(
    internal_pypi_url='https://pypi.internal.company.com/simple',
    fallback_pypi_url='https://pypi.org/simple',
    trusted_hosts=None,
    username=None,
    password=None,
    timeout=60,
    retries=5
):
    if trusted_hosts is None:
        trusted_hosts = ['pypi.internal.company.com']
    
    if username and password:
        from urllib.parse import urlparse, urlunparse
        parsed = urlparse(internal_pypi_url)
        internal_pypi_url = urlunparse((
            parsed.scheme,
            f'{username}:{password}@{parsed.netloc}',
            parsed.path,
            parsed.params,
            parsed.query,
            parsed.fragment
        ))
    
    return create_pip_config(
        internal_pypi_url=internal_pypi_url,
        fallback_pypi_url=fallback_pypi_url,
        trusted_hosts=trusted_hosts,
        timeout=timeout,
        retries=retries
    )


def create_pip_config_env_based():
    internal_pypi_url = os.environ.get(
        'PIP_INDEX_URL',
        'https://pypi.internal.company.com/simple'
    )
    
    fallback_pypi_url = os.environ.get(
        'PIP_EXTRA_INDEX_URL',
        'https://pypi.org/simple'
    )
    
    trusted_hosts_str = os.environ.get('PIP_TRUSTED_HOST', '')
    trusted_hosts = [h.strip() for h in trusted_hosts_str.split(',') if h.strip()]
    
    if not trusted_hosts:
        trusted_hosts = ['pypi.internal.company.com']
    
    timeout = int(os.environ.get('PIP_TIMEOUT', '60'))
    retries = int(os.environ.get('PIP_RETRIES', '5'))
    
    return create_pip_config(
        internal_pypi_url=internal_pypi_url,
        fallback_pypi_url=fallback_pypi_url,
        trusted_hosts=trusted_hosts,
        timeout=timeout,
        retries=retries
    )


def verify_pip_config():
    config_dir, config_file = get_pip_config_path()
    
    if not config_file.exists():
        return False, "Configuration file does not exist"
    
    try:
        config = configparser.ConfigParser()
        config.read(config_file)
        
        if 'install' not in config:
            return False, "Missing [install] section"
        
        if 'index-url' not in config['install']:
            return False, "Missing index-url in [install] section"
        
        return True, "Configuration is valid"
    except Exception as e:
        return False, f"Error reading configuration: {str(e)}"


def backup_existing_config():
    config_dir, config_file = get_pip_config_path()
    
    if config_file.exists():
        backup_file = config_file.with_suffix(config_file.suffix + '.backup')
        import shutil
        shutil.copy2(config_file, backup_file)
        return backup_file
    
    return None


def restore_config_from_backup():
    config_dir, config_file = get_pip_config_path()
    backup_file = config_file.with_suffix(config_file.suffix + '.backup')
    
    if backup_file.exists():
        import shutil
        shutil.copy2(backup_file, config_file)
        return True
    
    return False


def remove_pip_config():
    config_dir, config_file = get_pip_config_path()
    
    if config_file.exists():
        config_file.unlink()
        return True
    
    return False


def display_current_config():
    config_dir, config_file = get_pip_config_path()
    
    if not config_file.exists():
        return "No pip configuration file found"
    
    with open(config_file, 'r') as f:
        return f.read()


